// Test: very rough seas should instantly trigger black
async function testComputeSeaStatusBlackWaves() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 10,      // even with light wind
    windGusts: 12,
    waveHeight: 6.0,    // very rough seas — instant black trigger
    precipitation: 0,
    pressure: 1013,
    cloudCover: 30
  });

  assertEquals(result.level, 'black', 'Very rough seas should trigger black');
  assertEquals(result.score, 0, 'Black from instant trigger should be score 0');
  assert(result.reasons[0].includes('Very rough seas'), 'Should mention rough seas');
}
